import React, { useState } from "react";

function RouteForm() {
  // ← здесь объявляем состояния — они видны внутри компонента
  const [departure, setDeparture] = useState("");
  const [arrival,   setArrival]   = useState("");

  // ← обработчик теперь внутри компонента и видит состояния
  const handleSubmit = async (e) => {
    e.preventDefault();

    if (!departure.trim() || !arrival.trim()) {
      alert("Заполните оба поля");
      return;
    }

    try {
      const res = await fetch("http://localhost:5050/routes", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          departure_station: departure.trim(),   // trim() — хорошая идея
          arrival_station:   arrival.trim(),
        })
      });

      const data = await res.json();

      console.log("Статус:", res.status);
      console.log("Ответ:", data);

      if (!res.ok) {
        // здесь data может быть строкой или объектом — делаем надёжнее
        const errorMessage = data.message || data.error || JSON.stringify(data) || `Ошибка ${res.status}`;
        alert(errorMessage);
        return;
      }

      alert("Маршрут добавлен ✅");

      // ← очищаем поля после успеха
      setDeparture("");
      setArrival("");

    } catch (err) {
      console.error("Fetch error:", err);
      alert(`Ошибка соединения:\n${err.message}\n(скорее всего CORS, сервер выключен или неверный URL)`);
    }
  };

  return (
    <div>
      <h2>Add Route</h2>

      <form onSubmit={handleSubmit}>
        <input
          type="text"
          placeholder="Departure station"
          value={departure}
          onChange={(e) => setDeparture(e.target.value)}
        />

        <input
          type="text"
          placeholder="Arrival station"
          value={arrival}
          onChange={(e) => setArrival(e.target.value)}
        />

        <button type="submit">Add</button>
      </form>
    </div>
  );
}

export default RouteForm;
